#include <stdio.h>

typedef struct {
    char rue[50];
    char ville[30];
    int code_postal;
} Adresse;

typedef struct {
    char nom[30];
    int age;
    Adresse adresse;
} Personne;

void print_personne(const Personne *p) {
    printf("Nom : %s\n", p->nom);
    printf("Age : %d\n", p->age);
    printf("Rue : %s\n", p->adresse.rue);
    printf("Ville : %s (%d)\n", p->adresse.ville, p->adresse.code_postal);
}

int main(void) {
    Personne alice = {
        .nom = "Alice Dupont",
        .age = 28,
        .adresse = {
            .rue = "12 rue de la Paix",
            .ville = "Paris",
            .code_postal = 75001
        }
    };
    print_personne(&alice);
    return 0;
}

